<template><div class="page-container"><el-card><template #header><span>库存管理</span></template><el-form :inline="true"><el-form-item label="仓库"><el-select v-model="f.warehouse_id" clearable><el-option v-for="w in warehouses" :key="w.id" :label="w.name" :value="w.id"/></el-select></el-form-item><el-form-item label="搜索"><el-input v-model="f.search" placeholder="SKU/品名" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="sku" label="SKU" width="120"/><el-table-column prop="sku_name" label="品名" width="150"/><el-table-column prop="quantity" label="可用库存" width="120"/><el-table-column prop="locked_qty" label="锁定库存" width="120"/><el-table-column label="仓库"><template #default="{ row }">{{ row.warehouse_name || r.warehouse }}</template></el-table-column><el-table-column prop="updated_at" label="更新时间" width="160"/><el-table-column label="操作" width="100"><template #default="{ row }"><el-button size="small" @click="handleDetail(r)">调整</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { inventoryApi, warehouseApi } from '@/api/wms'; import { ElMessage } from 'element-plus'
const f = reactive({ warehouse_id: '', search: '' }); const list = ref([]); const loading = ref(false); const warehouses = ref([]); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { let [r1, r2] = await Promise.all([inventoryApi.list({ ...f, page: p.page }), warehouseApi.list()]); list.value = r1.data?.results || r1.data || []; p.total = r1.data?.count || 0; warehouses.value = r2.data?.results || r2.data || [] } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleDetail(r) { ElMessage.info(`调整库存: ${r.sku}`) }
onMounted(load)
</script>
